record.field:
# Recalcular todas las cantidades recibidas desde stock.move
fill_rate_lines = env['fill.rate.line'].search([])
for line in fill_rate_lines:
    line.update_received_quantity()

# Recalcular Fill Rate de todos los proveedores
partners = env['res.partner'].search([('fill_rate_history_ids', '!=', False)])
for partner in partners:
    partner._compute_fill_rate()
    partner._compute_supplier_class()

# Mostrar mensaje de éxito
action = {
    'type': 'ir.actions.client',
    'tag': 'display_notification',
    'params': {
        'title': '¡Listo!',
        'message': f'Se recalcularon {len(fill_rate_lines)} líneas y {len(partners)} proveedores',
        'type': 'success',
        'sticky': False,
    }
}

if records:
    for partner in records:
        # Actualizar cantidades recibidas de todas las líneas del proveedor
        partner.fill_rate_history_ids.update_received_quantity()

        # Recalcular fill rate y clasificación
        partner._compute_fill_rate()
        partner._compute_supplier_class()

    action = {
        'type': 'ir.actions.client',
        'tag': 'display_notification',
        'params': {
            'title': 'Recalculado',
            'message': f'Fill Rate actualizado correctamente para {len(records)} proveedor(es)',
            'type': 'success',
            'sticky': False,
        }
    }

# Usar las órdenes seleccionadas por el usuario
# Si seleccionó órdenes, usar esas; si no, buscar todas las que califiquen
if records:
    orders = records.filtered(lambda o: o.state in ['purchase', 'done'])
else:
    orders = env['purchase.order'].search([
        ('state', 'in', ['purchase', 'done']),
        ('fill_rate_created', '=', False)
    ])

# Procesar órdenes (el método maneja ValidationError internamente)
created_count = 0
errors = 0
processed = 0

for order in orders:
    try:
        # Solo procesar si no tiene fill rate creado
        if not order.fill_rate_created:
            order.create_missing_fill_rate_lines()
            created_count += len(order.fill_rate_line_ids)
            processed += 1
    except Exception as e:
        errors += 1
        continue

# Recalcular fill rate de proveedores afectados
partners = orders.mapped('partner_id')
for partner in partners:
    partner._compute_fill_rate()
    partner._compute_supplier_class()

# Mostrar resultado
if errors == 0:
    message = f'Se crearon {created_count} registros para {processed} órdenes de {len(orders)} seleccionadas. Afectados {len(partners)} proveedores.'
    msg_type = 'success'
else:
    message = f'Se crearon {created_count} registros para {processed} órdenes. {errors} órdenes tuvieron problemas (ver logs).'
    msg_type = 'warning'

action = {
    'type': 'ir.actions.client',
    'tag': 'display_notification',
    'params': {
        'title': '¡Completado!',
        'message': message,
        'type': msg_type,
        'sticky': True,
    }
}
